            $secret = @{
                Name = "db-password"
                LastRotated = "2026-03-01"
                RotationPolicyDays = 30
                RequiredByServices = @("app-server", "api-gateway")
            }
            $secret.Name | Should -Be "db-password"
            $secret.RotationPolicyDays | Should -Be 30
        }
    }

